import React, { Fragment, useState, useEffect } from "react";
import {
  Col,
  Card,
  CardHeader,
  CardBody,
  Form,
  Row,
  Media,
  Label,
  Input,
} from "reactstrap";
import SweetAlert from "sweetalert2";
import DataTable from "react-data-table-component";
import { H3, Btn, Breadcrumbs, H4 } from "../../../AbstractElements";
import { Link, useNavigate } from "react-router-dom";
import {
  getClientUrlDataToken,
  postClientUrlWithToken,
} from "../../../Utils/restUtils";
import {
  Add,
  Area,
  AreaList,
  Search,
  Filter,
  Brands,
  BrandLists,
  ProblemType,
  problemLists,
} from "../../../Constant";
import { useSelector } from "react-redux";
import {
    changeBrandStatus,
  changeBrandStatusRole,
  changeProblemTypeStatus,
  changeProblemTypeStatusRole,
  deleteArea,
  deleteAreaRole,
  deleteBrand,
  deleteBrandRole,
  deleteProblemType,
  deleteProblemTypeRole,
  showBrand,
  showBrandRole,
  showProblemsType,
  showProblemsTypeRole,
  viewArea,
  viewAreaRole,
} from "../../../CommonUrl";
import {
  AreaColumns,
  BrandColumns,
  problemTypeColumns,
} from "../../../Data/MockTable/SettingsTableHeader";
import Transparentspinner from "../../Common/Loader/Transparentspinner";
import { toast } from "react-toastify";

const ProblemTypeList = () => {
  const style2 = { width: 60, fontSize: 13, padding: 3, marginRight: "10px" };
  const authState = useSelector((state) => state.auth);
  const [areaList, setAreaList] = useState([]);
  const [searchKeyword, setSearchKeyword] = useState("");
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();
  const [resetPaginationToggle, setResetPaginationToggle] = useState(false);

  useEffect(() => {
    if (searchKeyword == "") {
      setLoading(true);
      areaData();
    }
  }, [searchKeyword]);

  const handleSearchInputChange = (event) => {
    setSearchKeyword(event.target.value);
  };

  const handleFilterSubmit = (event) => {
    event.preventDefault();
    setLoading(true);
    areaData();
  };

  const redirectToEditForm = (data) => {
    const editFormURL = `${process.env.PUBLIC_URL}/settings/edit-problem-type?id=${data.id}`;
    navigate(editFormURL);
  };

  const deleteAreaList = (brandId) => {
    SweetAlert.fire({
      title: "Confirm deletion?",
      text: "This action cannot be undone.",
      icon: "warning",
      showCancelButton: true,
      confirmButtonText: "Ok",
      cancelButtonText: "cancel",
      reverseButtons: true,
    }).then(async (result) => {
      setLoading(true);
      if (result.value) {
        const deleteRes = { problem_type_id: brandId };
        let brandDelete = await postClientUrlWithToken(
          authState.apiUrl,
          authState.userRole === 1 ? deleteProblemType : deleteProblemTypeRole,
          deleteRes
        );
        if (brandDelete?.status === 200) {
          if (brandDelete?.data?.status === true) {
            SweetAlert.fire(
              "Deleted!",
              "Your file has been deleted.",
              "success"
            );
            areaData();
          } else {
            SweetAlert.fire("Error", brandDelete?.data?.message, "error");
          }
        } else if (brandDelete?.status >= 400 && brandDelete?.status <= 405) {
          navigate(`${process.env.PUBLIC_URL}/pages/error/error-page1`);
        } else if (brandDelete?.status >= 500 && brandDelete?.status <= 505) {
          navigate(`${process.env.PUBLIC_URL}/pages/error/error-page4`);
        } else {
          navigate(`${process.env.PUBLIC_URL}/pages/error/error-page3`);
        }
      }
      setLoading(false);
    });
  };

  const handleSwitchToggle = async (event,brnadId) => {
    const reqSwitch = { problem_type_id: brnadId};
    const statusChange = await postClientUrlWithToken(
      authState.apiUrl,
      authState.userRole === 1 ? changeProblemTypeStatus : changeProblemTypeStatusRole,
      reqSwitch
    );
    if (statusChange?.status === 200) {
      if (statusChange.data.status === true) {
        toast.success(statusChange.data.message);
      } else {
        navigate(`${process.env.PUBLIC_URL}/pages/error/error-page4`);
      }
    } else if (statusChange.status >= 400 && statusChange.status <= 405) {
      navigate(`${process.env.PUBLIC_URL}/pages/error/error-page1`);
    } else if (statusChange.status >= 500 && statusChange.status <= 505) {
      navigate(`${process.env.PUBLIC_URL}/pages/error/error-page4`);
    } else {
      navigate(`${process.env.PUBLIC_URL}/pages/error/error-page3`);
    }
  };

  const areaData = async () => {
    setLoading(true);
    const data = await getClientUrlDataToken(
      authState.apiUrl,
      authState.userRole === 1 ? `${showProblemsType}?search=${searchKeyword}` : `${showProblemsTypeRole}?search=${searchKeyword}`
    );
    if (data.status === true) {
      setResetPaginationToggle(!resetPaginationToggle);

      setAreaList(
        data?.data?.data?.map((e, index) => {
          return {
            Si: index + 1,
            name: e?.name||'N/A',
            description: e?.description||'N/A',
            action: (
              <div>
                <span>
                  <Btn
                    attrBtn={{
                      style: style2,
                      color: "primary btn-xs",
                      type: "button",
                      onClick: () => redirectToEditForm(e),
                    }}
                  >
                    Edit{" "}
                  </Btn>
                </span>
                <span>
                  <Btn
                    attrBtn={{
                      style: style2,
                      className: "me-2",
                      color: "danger btn-xs",
                      type: "button",
                      onClick: () => {
                        deleteAreaList(e.id);
                      },
                    }}
                  >
                    Delete
                  </Btn>
                </span>
              </div>
            ),
            status: (
              <Media body className={`flex-grow-1 text-end icon-state`}>
                <Label className="switch">
                  <Input
                    type="checkbox"
                    defaultChecked={e.status === "active"}
                    onChange={(event) => handleSwitchToggle(event, e.id)}
                  />
                  <span className="switch-state"></span>
                </Label>
              </Media>
            ),
          };
        })
      );
      setLoading(false);
    } else if (data.status >= 400 && data.status <= 405) {
      navigate(`${process.env.PUBLIC_URL}/pages/error/error-page1`);
    } else if (data.status >= 500 && data.status <= 505) {
      navigate(`${process.env.PUBLIC_URL}/pages/error/error-page4`);
    } else {
      navigate(`${process.env.PUBLIC_URL}/pages/error/error-page3`);
    }
    setLoading(false);
  };

  return (
    <Fragment>
      {loading && <Transparentspinner />}
      <Breadcrumbs mainTitle={ProblemType} parent="Settings" title={ProblemType} />
      <Card className="cardWidth">
        <CardHeader
          style={{
            margin: "-5px 0 -20px",
            display: "flex",
            alignItems: "center",
            justifyContent: "space-between",
          }}
        >
          <H3>{problemLists}</H3>
          <div>
            <Link
              to={`${process.env.PUBLIC_URL}/settings/add-problem-type`}
              className="btn btn-primary"
            >
              {Add}
            </Link>
          </div>
        </CardHeader>

        <CardBody>
          <span className="custom-span">
            <Form
              className="needs-validation"
              noValidate
              onSubmit={handleFilterSubmit}
            >
              <Row className="ps-3 mb-4 custom-search-filter align-items-center">
                <Col xs="6" sm="4" md="2" lg="2">
                  <input
                    className="form-control"
                    placeholder={Search}
                    type="text"
                    value={searchKeyword}
                    onChange={handleSearchInputChange}
                  />
                </Col>
                <Col xs="6" sm="6" md="4" lg="3">
                  <Btn
                    className="custom-filter-btn"
                    attrBtn={{ color: "primary" }}
                    type="submit"
                  >
                    {Filter}
                  </Btn>
                </Col>
              </Row>
            </Form>
          </span>
          <div className="order-history table-responsive">
            <DataTable
              data={areaList}
              columns={[
                {
                  name: <H4>Sl.No</H4>,
                  selector: (row, index) => index + 1,
                  width: "70px",
                  center: true,
                  sortable: false,
                },
                ...problemTypeColumns,
              ]}
              pagination
              defaultSortAsc
              paginationRowsPerPageOptions={[10, 25, 50, 100]}
              fixedHeader
              style={{ border: "1px solid" }}
            />
          </div>
        </CardBody>
      </Card>
    </Fragment>
  );
};

export default ProblemTypeList;
